parameters.jsCode:
const formData = items[0].json;
const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

// Extract language code from dropdown selection (e.g., "Spanish (ES)" -> "ES")
const languageSelection = formData['Language'] || 'Spanish (ES)';
const langCodeMatch = languageSelection.match(/\(([A-Z]{2})\)/);
const langCode = langCodeMatch ? langCodeMatch[1] : 'ES';

const email = formData['Your Email'] || '';
const message = (formData['Your Question'] || '').trim();

const isValidEmail = emailRegex.test(email);
const hasMessage = message.length > 5;

let errorReason = null;
if (!isValidEmail) errorReason = 'invalid_email';
else if (!hasMessage) errorReason = 'empty_message';

return {
  customerEmail: email,
  customerMessage: message,
  customerLanguage: langCode,
  isValid: !errorReason,
  errorReason: errorReason,
  timestamp: new Date().toISOString()
};

